using Microsoft.EntityFrameworkCore;

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 breaking change #1: Default discriminator property renamed
        // from "Discriminator" to "$type". Existing documents use "Discriminator",
        // so explicitly configure the old name to preserve compatibility.
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // EF Core 9 breaking change #2: The `id` property no longer includes the
        // discriminator value (was "Session|123", now just "123"). Existing documents
        // have the old compound format; opt-in to preserve the old id layout.
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }
}

class Session
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
}

using Microsoft.EntityFrameworkCore;

class CosmosQueryService
{
    // EF Core 9 breaking change #3: Cosmos DB provider no longer supports
    // synchronous I/O. ToList(), SaveChanges(), etc. now throw.
    // All queries and saves must use async equivalents.
    async Task<List<Session>> GetSessionsAsync(CosmosDbContext db)
    {
        // Before (EF Core 8): db.Sessions.ToList()
        return await db.Sessions.ToListAsync();
    }

    async Task SaveSessionAsync(CosmosDbContext db, Session session)
    {
        db.Sessions.Add(session);
        // Before (EF Core 8): db.SaveChanges()
        await db.SaveChangesAsync();
    }
}

